module master_slave_d_latch (  
    input wire D,  
    input wire CLK,  
    output reg Q  
);  
    reg master;  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin  
        master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= master;  
    end  
endmodule
